  // Sanitize a batch of HTML strings
  // ----------------------------------------------------------------
  sanitizeBatch(
    htmls: string[],
    uids?: string[]
  ): Array<{ cleanHtml: string; report: SanitizationReport }> {
    return htmls.map((html, i) => {
      const uid = uids?.[i] ?? `batch-${i}`;
      return this.sanitize(html, uid);
