  private normalizeHeaderName(name: string): string {
    if (!name) return '';
    return name
      .trim()
      .toLowerCase()
      .replace(/([a-z])([A-Z])/g, '$1-$2')   // camelCase -> kebab-case
      .replace(/^[_-]/, '')
      .replace(/[_]+/g, '-')
      .trim();
