export function getWSGateway(): WSGateway | null {
  return _gateway;
}

export function initWSGateway(fastify: FastifyInstance): WSGateway {
  if (!_gateway) {
    _gateway = new WSGateway(fastify);
  }
  return _gateway;
}

export function resetWSGateway(): void {
  if (_gateway) {
    void _gateway.stop();
    _gateway = null;
  }
