      // Stream-like with 'data'.
      await new Promise<void>((resolve, reject) => {
        (stream as Readable).on('data', (chunk: Buffer | Uint8Array) => {
          chunks.push(chunk instanceof Buffer ? chunk : Buffer.from(chunk));
