import MailParser from 'mailparser';
import { Readable } from 'node:stream';

import type { MimePipelineConfig, MimeAddress } from './types';

export interface ParsedMimeRaw {
  messageId: string;
  subject: string;
  from: MimeAddress[];
  to: MimeAddress[];
  cc: MimeAddress[];
  bcc: MimeAddress[];
  replyTo?: MimeAddress[];
  date: string;
  inReplyTo?: string;
  references: string[];
  text: string;
  html: string;
  textPlain: string;
  attachments: MimeRawAttachment[];
  headers: MimeRawHeaders;
  rawHeaders: string;
}

export type MimeAddressEntry = MimeAddress;

export interface MimeRawAttachment {
  filename: string;
  contentType: string;
  contentLength: number;
  content: Buffer;
  contentId?: string;
  disposition: 'inline' | 'attachment';
  related?: boolean;
}

export interface MimeRawHeaders {
  all: Record<string, string[]>;
  raw: string;
}

