// ------------------------------------------------------------------
// Known XSS vectors to detect
// ------------------------------------------------------------------
const XSS_PATTERNS = [
  /javascript\s*:/gi,
  /vbscript\s*:/gi,
  /data\s*:text\/html/gi,
  /on\w+\s*=/gi,
  /expression\s*\(/gi,
  /url\s*\(/gi,
  /@import/gi,
  /<script/gi,
