  'a', 'img', 'abbr', 'cite', 'del', 'ins', 'q', 'sub', 'sup',
  'font', 'small', 'big', 'tt', 'mark', 'rp', 'rt', 'rtc', 'ruby',
  'center', 'dfn', 'kbd', 'samp', 'var', 'bdo',
