// ------------------------------------------------------------------
// White-listed attributes
// ------------------------------------------------------------------
const ALLOWED_ATTRIBUTES: Record<string, string[]> = {
  a: ['href', 'title', 'rel', 'target'],
  img: ['src', 'alt', 'width', 'height', 'style'],
  blockquote: ['cite'],
  del: ['cite'],
