    } catch {
      // Non-critical — pool cleanup can happen lazily
    }

    auditLogger.info('[WS] Client disconnected', {
      actor_id: client.userId,
      metadata: {
        clientId: client.id,
        durationMs: Date.now() - client.connectedAt,
      },
    });
  }

