  // Broadcast to ALL connected clients (admin/system events)
  broadcast(message: Record<string, unknown>): void {
    for (const [, userSet] of this.userSockets) {
      for (const ws of userSet.values()) {
        this.safeSend(ws, message);
      }
    }
