  // Stats
  // ----------------------------------------------------------------
  getStats(): { total: number; byUser: Record<string, number> } {
    const byUser: Record<string, number> = {};
    for (const [, client] of this.clients) {
      byUser[client.userId] = (byUser[client.userId] || 0) + 1;
    }
    return { total: this.clients.size, byUser };
